 15	} from '@patternfly/react-charts/victory';
 16	import chart_color_black_200 from '@patternfly/react-tokens/dist/esm/chart_color_black_200';
 17	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
 18	
 19	import { tickLabels } from '../ChartLabels/styleOverrides';
 20	import ComponentReady from '../ComponentReady/ComponentReady';
 21	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 22	import {
 23	  findNetworkMaxYValue,
 24	  formatNetworkYTick,
 25	  MILLISECONDS_MULTIPLIER,
 26	  tickFormat,
 27	  TICKS_COUNT,
 28	} from '../utils/utils';
 29	
 30	type NetworkThresholdSingleSourceChartProps = {
 31	  data: PrometheusResult[];
 32	  link: string;
 33	};
 34	
 35	const NetworkThresholdSingleSourceChart: FC<NetworkThresholdSingleSourceChartProps> = ({
 36	  data,
 37	  link,
 38	}) => {
 39	  const { currentTime, duration, timespan } = useDuration();
 40	  const { height, ref, width } = useResponsiveCharts();
 41	
 42	  const chartData =
 43	    !isEmpty(data) &&
 44	    data?.map((obj) => {
 45	      return (obj?.values || [])?.map(([x, y]) => {
 46	        return {
 47	          name: obj?.metric?.interface,
 48	          x: new Date(x * MILLISECONDS_MULTIPLIER),
 49	          y: Number(y),
 50	        };
 51	      });
 52	    });
 53	  const isReady = !isEmpty(chartData);
 54	  const Ymax = findNetworkMaxYValue(chartData);
 55	
 56	  const CursorVoronoiContainer = createContainer('voronoi', 'cursor');
 57	  const legendData =
 58	    !isEmpty(chartData) &&
 59	    chartData?.map((newChartdata, index) => {
 60	      return { childName: newChartdata?.[index]?.name, name: newChartdata?.[index]?.name };
 61	    });
 62	
 63	  return (
 64	    <ComponentReady isReady={isReady} linkToMetrics={link}>
 65	      <div className="util-threshold-chart" ref={ref}>
 66	        <Link to={link}>
 67	          <Chart
 68	            containerComponent={
 69	              <CursorVoronoiContainer
 70	                labelComponent={
 71	                  <ChartLegendTooltip
 72	                    title={(datum) =>
 73	                      datum?.x?.getHours() + ':' + String(datum?.x?.getMinutes())?.padStart(2, '0')
 74	                    }
 75	                    legendData={legendData}
 76	                  />
 77	                }
 78	                labels={({ datum }) => {
 79	                  return `${xbytes(datum?.y, {
 80	                    fixed: 2,
 81	                    iec: true,
 82	                  })}ps`;
 83	                }}
 84	                cursorDimension="x"
 85	                mouseFollowTooltips
 86	                voronoiDimension="x"
 87	              />
 88	            }
 89	            domain={{
 90	              x: [currentTime - timespan, currentTime],
 91	              y: [0, Ymax + 1],
 92	            }}
 93	            height={height}
 94	            padding={{ bottom: 60, left: 70, right: 60, top: 30 }}
 95	            scale={{ x: 'time', y: 'linear' }}
 96	            themeColor={ChartThemeColor.multiUnordered}
 97	            width={width}
 98	          >
 99	            <ChartAxis
100	              style={{
101	                grid: {
102	                  stroke: chart_color_black_200.value,
103	                },
104	                tickLabels,
105	              }}
106	              dependentAxis
107	              tickFormat={formatNetworkYTick}
108	              tickValues={[0, Ymax]}
109	            />
110	            <ChartAxis
111	              style={{
112	                tickLabels: { padding: 2, ...tickLabels },
113	                ticks: { stroke: 'transparent' },
114	              }}
115	              axisComponent={<></>}
116	              tickCount={TICKS_COUNT}
117	              tickFormat={tickFormat(duration, currentTime)}
118	            />
119	            <ChartGroup>
120	              {isReady &&
121	                chartData?.map((newChartdata) => (
122	                  <ChartLine
123	                    data={newChartdata}
124	                    key={newChartdata?.[0]?.name}
125	                    name={newChartdata?.[0]?.name}
126	                    themeColor={ChartThemeColor.multiUnordered}
127	                  />
128	                ))}
129	            </ChartGroup>
130	          </Chart>
131	        </Link>
132	      </div>
133	    </ComponentReady>
134	  );
135	};
136	export default NetworkThresholdSingleSourceChart;

